/**
 * Lightweight Markdown → HTML parser for the DeepSeek Markdown Enhancer.
 * Bundled locally (no CDN) for Manifest V3 remote-code safety.
 * Exposes window.marked.parse(src) to mirror the marked.js API surface we need.
 */
(function (global) {
  "use strict";

  function escapeHtml(text) {
    return String(text)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  function inline(text) {
    let s = escapeHtml(text);
    // code spans first so markers inside them aren't processed
    s = s.replace(/`([^`]+)`/g, "<code>$1</code>");
    s = s.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
    s = s.replace(/__([^_]+)__/g, "<strong>$1</strong>");
    s = s.replace(/(^|[^*])\*([^*\n]+)\*/g, "$1<em>$2</em>");
    s = s.replace(/(^|[^_])_([^_\n]+)_/g, "$1<em>$2</em>");
    s = s.replace(/~~([^~]+)~~/g, "<del>$1</del>");
    s = s.replace(
      /!\[([^\]]*)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)/g,
      '<img src="$2" alt="$1" title="$3" />'
    );
    s = s.replace(
      /\[([^\]]+)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)/g,
      '<a href="$2" title="$3" target="_blank" rel="noopener noreferrer">$1</a>'
    );
    return s;
  }

  function parseTable(rows) {
    if (rows.length < 2) return null;
    const sep = rows[1];
    if (!/^\|?\s*:?-+:?\s*(\|\s*:?-+:?\s*)+\|?\s*$/.test(sep)) return null;

    function cells(line) {
      return line
        .replace(/^\|/, "")
        .replace(/\|$/, "")
        .split("|")
        .map((c) => c.trim());
    }

    const headers = cells(rows[0]);
    let html = "<table><thead><tr>";
    headers.forEach((h) => {
      html += "<th>" + inline(h) + "</th>";
    });
    html += "</tr></thead><tbody>";
    for (let i = 2; i < rows.length; i++) {
      const cols = cells(rows[i]);
      html += "<tr>";
      for (let j = 0; j < headers.length; j++) {
        html += "<td>" + inline(cols[j] || "") + "</td>";
      }
      html += "</tr>";
    }
    html += "</tbody></table>";
    return html;
  }

  function parse(src) {
    const lines = String(src || "").replace(/\r\n?/g, "\n").split("\n");
    const out = [];
    let i = 0;

    while (i < lines.length) {
      const line = lines[i];

      // fenced code
      const fence = line.match(/^(`{3,}|~{3,})(.*)$/);
      if (fence) {
        const mark = fence[1][0];
        const lang = (fence[2] || "").trim();
        const buf = [];
        i++;
        while (i < lines.length && !new RegExp("^" + mark + "{3,}\\s*$").test(lines[i])) {
          buf.push(lines[i]);
          i++;
        }
        i++; // closing fence
        const cls = lang ? ' class="language-' + escapeHtml(lang) + '"' : "";
        out.push(
          "<pre><code" + cls + ">" + escapeHtml(buf.join("\n")) + "</code></pre>"
        );
        continue;
      }

      // horizontal rule
      if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
        out.push("<hr />");
        i++;
        continue;
      }

      // headings
      const heading = line.match(/^(#{1,6})\s+(.*)$/);
      if (heading) {
        const level = heading[1].length;
        out.push("<h" + level + ">" + inline(heading[2]) + "</h" + level + ">");
        i++;
        continue;
      }

      // blockquote
      if (/^>\s?/.test(line)) {
        const buf = [];
        while (i < lines.length && /^>\s?/.test(lines[i])) {
          buf.push(lines[i].replace(/^>\s?/, ""));
          i++;
        }
        out.push("<blockquote>" + parse(buf.join("\n")) + "</blockquote>");
        continue;
      }

      // unordered list
      if (/^(\s*)([-*+])\s+/.test(line)) {
        const items = [];
        while (i < lines.length && /^(\s*)([-*+])\s+/.test(lines[i])) {
          items.push("<li>" + inline(lines[i].replace(/^(\s*)([-*+])\s+/, "")) + "</li>");
          i++;
        }
        out.push("<ul>" + items.join("") + "</ul>");
        continue;
      }

      // ordered list
      if (/^(\s*)\d+\.\s+/.test(line)) {
        const items = [];
        while (i < lines.length && /^(\s*)\d+\.\s+/.test(lines[i])) {
          items.push("<li>" + inline(lines[i].replace(/^(\s*)\d+\.\s+/, "")) + "</li>");
          i++;
        }
        out.push("<ol>" + items.join("") + "</ol>");
        continue;
      }

      // table
      if (line.includes("|") && i + 1 < lines.length && /\|?\s*:?-+:?\s*\|/.test(lines[i + 1])) {
        const rows = [];
        while (i < lines.length && lines[i].includes("|")) {
          rows.push(lines[i]);
          i++;
        }
        const table = parseTable(rows);
        if (table) {
          out.push(table);
          continue;
        }
        // fallback: treat as paragraph lines
        rows.forEach((r) => out.push("<p>" + inline(r) + "</p>"));
        continue;
      }

      // blank line
      if (/^\s*$/.test(line)) {
        i++;
        continue;
      }

      // paragraph (merge consecutive non-special lines)
      const buf = [line];
      i++;
      while (
        i < lines.length &&
        !/^\s*$/.test(lines[i]) &&
        !/^(#{1,6})\s+/.test(lines[i]) &&
        !/^(`{3,}|~{3,})/.test(lines[i]) &&
        !/^>\s?/.test(lines[i]) &&
        !/^(\s*)([-*+])\s+/.test(lines[i]) &&
        !/^(\s*)\d+\.\s+/.test(lines[i]) &&
        !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i])
      ) {
        buf.push(lines[i]);
        i++;
      }
      out.push("<p>" + buf.map(inline).join("<br />") + "</p>");
    }

    return out.join("\n") || "<p></p>";
  }

  const api = { parse: parse, marked: parse };
  if (typeof module !== "undefined" && module.exports) {
    module.exports = api;
  }
  global.marked = api;
})(typeof window !== "undefined" ? window : this);
